#include<bits/stdc++.h>
using namespace std;
int a[100010];
struct node
{
    int l,r,type,cnt;
    bool operator<(const node&b)const
    {
        if(l!=b.l)
        {
            return l<b.l;
        }
        if(type!=b.type)
        {
            return type<b.type;
        }
        if(r!=b.r)
        {
            return r<b.r;
        }
        return cnt<b.cnt;
    }
};
struct node1
{
    int r,t;
    bool operator<(const node1&b)const
    {
        if(t!=b.t)
        {
            return t>b.t;
        }
        return r>b.r;
    }
};
vector<node> v;
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n,k;
        scanf("%d%d",&n,&k);
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
        }
        sort(a+1,a+1+n);
        v.clear();
        for(int i=1;i<=n;i++)
        {
            v.push_back((node){a[i],0,1,0});
        }
        for(int i=1;i<=k;i++)
        {
            int l,r,t;
            scanf("%d%d%d",&l,&r,&t);
            int tmp=upper_bound(a+1,a+1+n,r)-lower_bound(a+1,a+1+n,l)-t;
            v.push_back((node){l,r,0,tmp});
        }
        sort(v.begin(),v.end());
        priority_queue<node1> q;
        int ans=0;
        for(auto i:v)
        {
            int l=i.l,r=i.r,type=i.type,cnt=i.cnt;
            if(type==0)
            {
                q.push((node1){r,ans+cnt});
            }
            else
            {
                while(!q.empty()&&q.top().r<l)
                {
                    q.pop();
                }
                if(q.empty()||q.top().t>ans)
                {
                    ans++;
                }
            }
        }
        printf("%d\n",ans);
    }
    return 0;
}
